CREATE TYPE "Role" AS ENUM (
  'Student',
  'Advisor'
);

CREATE TYPE "StatusLogin" AS ENUM (
  'Taken_Action ',
  'Confirmed'
);

CREATE TYPE "StatusManageAccount" AS ENUM (
  'Edit_Permissions',
  'Account_Deleted.'
);

CREATE TYPE "StatusQueueALL" AS ENUM (
  'Awaiting_Approved',
  'Approved',
  'Reschedule_Queue',
  'Cancel_Queue'
);

CREATE TABLE "AdminProfile" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "username" varchar(20) NOT NULL,
  "password" varchar(255) NOT NULL,
  "created_at" TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE "LoginUser" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "uuid_line" varchar(255) UNIQUE NOT NULL,
  "profile_image" varchar(255) NOT NULL,

  "prefix" varchar(50) NOT NULL,
  "fristName" varchar(100) NOT NULL,
  "LastName" varchar(100) NOT NULL,
  "major" varchar(100) NOT NULL,
  
  "role_user" "Role",
  "status" "StatusLogin",
  "admin_id" integer,

  "created_at" TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE "ManageUserAccounts" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "status_permissions" "StatusLogin",
  "status_ManageAccount" "StatusManageAccount",
  "admin_id" integer,
  "created_at" TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE "StudentsProfile" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "major" varchar(255),
  "login_permissionsID" integer,
  "manage_user_accountsID" integer,
  "created_at" TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE "Advisorsprofile" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "major" varchar(255),
  "login_permissionsID" integer,
  "manage_user_accountsID" integer,
  "created_at" TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE "ConsultationTime" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "consultationDate" date NOT NULL,
  "consultation_start_time" time NOT NULL,
  "consultation_end_time" time NOT NULL,
  "advisors_profile_id" integer,
  "created_at" TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE "QueueBooking" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "booking_date" date NOT NULL,
  "booking_time" time NOT NULL,
  "consultation_type" varchar(100) NOT NULL,
  "problem_detail" text NOT NULL,
  "status_QueueBooking" "StatusQueueALL",
  "students_profile_id" integer,
  "advisors_profile_id" integer,
  "consultation_time_id" integer,
  "created_at" TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE "CancelQueue" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "Status_ManageQueue" "StatusQueueALL",
  "students_profile_id" integer,
  "advisors_profile_id" integer,
  "queue_booking_id" integer,
  "created_at" TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE "QueuePostponement" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "old_date" date NOT NULL,
  "old_time" time NOT NULL,
  "Status_QueuePostponement" "StatusQueueALL",
  "students_profile_id" integer,
  "advisors_profile_id" integer,
  "queue_booking_id" integer,
  "created_at" TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE "QueuePostponement_Students" (
  "reschedule_reason_Students" varchar(100) NOT NULL,
  "queue_postponement_id" integer NOT NULL,
  "created_at" TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE "QueuePostponement_Advisors" (
  "reschedule_reason_Advisors" varchar(100) NOT NULL,
  "queue_postponement_id" integer NOT NULL,
  "created_at" TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON COLUMN "LoginUser"."role_user" IS 'สิทธิ์การเข้าสู่ระบบ (ผู้ใช้ทั่วไป)';

ALTER TABLE "LoginUser" ADD CONSTRAINT "one_to_many" FOREIGN KEY ("admin_id") REFERENCES "AdminProfile" ("id") DEFERRABLE INITIALLY IMMEDIATE;

