ALTER TABLE "QueueBooking" ADD CONSTRAINT "one_to_many" FOREIGN KEY ("advisors_profile_id") REFERENCES "Advisorsprofile" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "QueueBooking" ADD CONSTRAINT "many_to_one" FOREIGN KEY ("consultation_time_id") REFERENCES "ConsultationTime" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "CancelQueue" ADD CONSTRAINT "one_to_one" FOREIGN KEY ("students_profile_id") REFERENCES "StudentsProfile" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "CancelQueue" ADD CONSTRAINT "one_to_many" FOREIGN KEY ("advisors_profile_id") REFERENCES "Advisorsprofile" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "CancelQueue" ADD CONSTRAINT "many_to_one" FOREIGN KEY ("queue_booking_id") REFERENCES "QueueBooking" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "QueuePostponement" ADD CONSTRAINT "one_to_one" FOREIGN KEY ("students_profile_id") REFERENCES "StudentsProfile" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "QueuePostponement" ADD CONSTRAINT "one_to_many" FOREIGN KEY ("advisors_profile_id") REFERENCES "Advisorsprofile" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "QueuePostponement" ADD CONSTRAINT "many_to_one" FOREIGN KEY ("queue_booking_id") REFERENCES "QueueBooking" ("id") DEFERRABLE INITIALLY IMMEDIATE;

